<template>
	<div ref="containerRef" class="relative size-full">
		<div
			v-for="item in grid"
			:key="item.id"
			:data-key="item.id"
			class="absolute box-content"
			:style="{ willChange: 'transform, width, height, opacity' }"
			@click="openUrl(item.url)"
			@mouseenter="(e) => handleMouseEnter(item.id, e.currentTarget)"
			@mouseleave="(e) => handleMouseLeave(item.id, e.currentTarget)"
		>
			<div
				class="relative size-full bg-cover bg-center rounded-[10px] shadow-[0px_10px_50px_-10px_rgba(0,0,0,0.2)] uppercase text-[10px] leading-[10px]"
				:style="{ backgroundImage: `url(${item.img})` }"
			>
				<div
					v-if="colorShiftOnHover"
					class="color-overlay absolute inset-0 rounded-[10px] bg-gradient-to-tr from-pink-500/50 to-sky-500/50 opacity-0 pointer-events-none"
				/>
			</div>
		</div>
	</div>
</template>

<script setup>
import { useMediaQuery } from "@vueuse/core";
import { gsap } from "gsap";
import { computed, nextTick, onMounted, onUnmounted, ref, watchEffect } from "vue";
const props = defineProps({
  items: { type: Array, required: true },
  ease: { type: String, required: false, default: "power3.out" },
  duration: { type: Number, required: false, default: 0.6 },
  stagger: { type: Number, required: false, default: 0.05 },
  animateFrom: { type: String, required: false, default: "bottom" },
  scaleOnHover: { type: Boolean, required: false, default: true },
  hoverScale: { type: Number, required: false, default: 0.95 },
  blurToFocus: { type: Boolean, required: false, default: true },
  colorShiftOnHover: { type: Boolean, required: false, default: false }
});
const useMedia = (queries, values, defaultValue) => {
  const matches = queries.map((q) => useMediaQuery(q, { ssrWidth: 768 }));
  const value = computed(() => {
    const index = matches.findIndex((match) => match.value);
    return index !== -1 ? values[index] : defaultValue;
  });
  return value;
};
const useMeasure = () => {
  const containerRef2 = ref(null);
  const size2 = ref({ width: 0, height: 0 });
  let resizeObserver = null;
  onMounted(() => {
    if (!containerRef2.value) return;
    resizeObserver = new ResizeObserver(([entry]) => {
      const { width, height } = entry.contentRect;
      size2.value = { width, height };
    });
    resizeObserver.observe(containerRef2.value);
  });
  onUnmounted(() => {
    if (resizeObserver) {
      resizeObserver.disconnect();
    }
  });
  return [containerRef2, size2];
};
const preloadImages = async (urls) => {
  if (import.meta.server) return;
  await Promise.all(
    urls.map(
      (src) => new Promise((resolve) => {
        const img = new Image();
        img.src = src;
        img.onload = img.onerror = () => resolve();
      })
    )
  );
};
const columns = useMedia(
  ["(min-width:1500px)", "(min-width:1000px)", "(min-width:600px)", "(min-width:400px)"],
  [5, 4, 3, 2],
  1
);
const [containerRef, size] = useMeasure();
const imagesReady = ref(false);
const hasMounted = ref(false);
const grid = computed(() => {
  if (!size.value.width) return [];
  const colHeights = [columns.value].fill(0);
  const gap = 16;
  const totalGaps = (columns.value - 1) * gap;
  const columnWidth = (size.value.width - totalGaps) / columns.value;
  return props.items.map((child) => {
    const col = colHeights.indexOf(Math.min(...colHeights));
    const x = col * (columnWidth + gap);
    const height = child.height / 2;
    const y = colHeights[col];
    colHeights[col] += height + gap;
    return { ...child, x, y, w: columnWidth, h: height };
  });
});
const openUrl = (url) => {
  window.open(url, "_blank", "noopener");
};
const getInitialPosition = (item) => {
  const containerRect = containerRef.value?.getBoundingClientRect();
  if (!containerRect) return { x: item.x, y: item.y };
  let direction = props.animateFrom;
  if (props.animateFrom === "random") {
    const dirs = ["top", "bottom", "left", "right"];
    direction = dirs[Math.floor(Math.random() * dirs.length)];
  }
  switch (direction) {
    case "top":
      return { x: item.x, y: -200 };
    case "bottom":
      return { x: item.x, y: window.innerHeight + 200 };
    case "left":
      return { x: -200, y: item.y };
    case "right":
      return { x: window.innerWidth + 200, y: item.y };
    case "center":
      return {
        x: containerRect.width / 2 - item.w / 2,
        y: containerRect.height / 2 - item.h / 2
      };
    default:
      return { x: item.x, y: item.y + 100 };
  }
};
const handleMouseEnter = (id, element) => {
  if (props.scaleOnHover) {
    gsap.to(`[data-key="${id}"]`, {
      scale: props.hoverScale,
      duration: 0.3,
      ease: "power2.out"
    });
  }
  if (props.colorShiftOnHover) {
    const overlay = element.querySelector(".color-overlay");
    if (overlay) gsap.to(overlay, { opacity: 0.3, duration: 0.3 });
  }
};
const handleMouseLeave = (id, element) => {
  if (props.scaleOnHover) {
    gsap.to(`[data-key="${id}"]`, {
      scale: 1,
      duration: 0.3,
      ease: "power2.out"
    });
  }
  if (props.colorShiftOnHover) {
    const overlay = element.querySelector(".color-overlay");
    if (overlay) gsap.to(overlay, { opacity: 0, duration: 0.3 });
  }
};
watchEffect(() => {
  preloadImages(props.items.map((i) => i.img)).then(() => {
    imagesReady.value = true;
  });
});
watchEffect(() => {
  if (!imagesReady.value) return;
  const currentGrid = grid.value;
  void props.items.length;
  void columns.value;
  void size.value.width;
  if (!currentGrid.length) return;
  nextTick(() => {
    currentGrid.forEach((item, index) => {
      const selector = `[data-key="${item.id}"]`;
      const animProps = { x: item.x, y: item.y, width: item.w, height: item.h };
      if (!hasMounted.value) {
        const start = getInitialPosition(item);
        gsap.fromTo(
          selector,
          {
            opacity: 0,
            x: start.x,
            y: start.y,
            width: item.w,
            height: item.h,
            ...props.blurToFocus && { filter: "blur(10px)" }
          },
          {
            opacity: 1,
            ...animProps,
            ...props.blurToFocus && { filter: "blur(0px)" },
            duration: 0.8,
            ease: "power3.out",
            delay: index * props.stagger
          }
        );
      } else {
        gsap.to(selector, {
          ...animProps,
          duration: props.duration,
          ease: props.ease,
          overwrite: "auto"
        });
      }
    });
    hasMounted.value = true;
  });
});
</script>
